import React, { useState, useContext } from 'react';
import { AuthContext } from '../context/AuthContext';
import { ROLES } from '../utils/helpers';
// Đã xóa dòng import './LoginForm.css'; để tránh lỗi

const LoginForm = () => {
  const { login } = useContext(AuthContext);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [selectedRole, setSelectedRole] = useState(ROLES.STAFF);

  const handleSubmit = (e) => {
    e.preventDefault();
    login(username, selectedRole);
  };

  return (
    <div className="flex justify-center items-center h-screen bg-gray-100">
      <form onSubmit={handleSubmit} className="bg-white p-8 rounded shadow-md w-96">
        <h2 className="text-2xl font-bold mb-6 text-center text-blue-600">Đăng Nhập</h2>
        
        <div className="mb-4">
          <label className="block mb-2 font-medium">Tên đăng nhập:</label>
          <input 
            type="text" 
            className="w-full border p-2 rounded"
            value={username} 
            onChange={(e) => setUsername(e.target.value)} 
            required 
          />
        </div>

        <div className="mb-4">
          <label className="block mb-2 font-medium">Mật khẩu:</label>
          <input 
            type="password" 
            className="w-full border p-2 rounded"
            value={password} 
            onChange={(e) => setPassword(e.target.value)} 
            required 
          />
        </div>

        <div className="mb-6">
          <label className="block mb-2 font-medium">Vai trò (Test):</label>
          <select 
            className="w-full border p-2 rounded"
            value={selectedRole} 
            onChange={(e) => setSelectedRole(e.target.value)}
          >
            <option value={ROLES.STAFF}>Nhân sự (Staff)</option>
            <option value={ROLES.OPERATIONAL_ADMIN}>Operational Admin</option>
            <option value={ROLES.REGULATORY_ADMIN}>Regulatory Admin</option>
            <option value={ROLES.CHIEF_ADMIN}>Chief Admin</option>
          </select>
        </div>

        <button type="submit" className="w-full bg-blue-600 text-white p-2 rounded hover:bg-blue-700 transition">
          Đăng Nhập
        </button>
      </form>
    </div>
  );
};

export default LoginForm;
